const items = $input.all();
const results = [];

for (const item of items) {
  const msg = item.json;
  let body = '';

  function decodeB64(data) {
    if (!data) return '';
    return Buffer.from(data.replace(/-/g, '+').replace(/_/g, '/'), 'base64').toString('utf-8');
  }
  function findTextPlain(part) {
    if (!part) return '';
    if (part.mimeType === 'text/plain' && part.body && part.body.data) return decodeB64(part.body.data);
    if (part.parts) { for (const sub of part.parts) { const r = findTextPlain(sub); if (r) return r; } }
    return '';
  }

  if (msg.payload) body = findTextPlain(msg.payload);
  if (!body && msg.snippet) body = msg.snippet;
  if (!body || !body.includes('SOLICITUD DE SERVICIO')) continue;

  // === NORMALIZACIÓN GLOBAL ===
  // Quitar asteriscos (formato forwarded HTML→text: *bold* → bold)
  body = body.replace(/\*/g, '');
  // Doble colon
  body = body.replace(/::/g, ':');
  // Normalizar "SOLICITUD DE SERVICIO" (singular) para que pase el check anterior
  // ya pasó

  const get = (pat) => { const m = body.match(pat); return m ? m[1].trim() : ''; };
  const empresas = get(/Empresa\(s\):\s*([^\r\n]+)/i);
  const zonas = get(/Zona\(s\):\s*([^\r\n]+)/i);
  const origenesRaw = get(/Origen\(es\):\s*([^\r\n]+)/i);
  const fechaCargue = get(/Fecha de Cargue:\s*([^\r\n,]+)/i);
  const cantPedidos = parseInt(get(/Cantidad de pedidos:\s*(\d+)/i)) || 0;
  const pesoTotal = get(/Peso Total Transportado:\s*([\d.,]+)/i);
  const valorTotal = get(/Valor Total Mercancía:\s*\$?([\d.,]+)/i);

  const hdrs = msg.payload?.headers || [];
  const subjectH = hdrs.find(h => h.name === 'Subject');
  const subject = subjectH ? subjectH.value : '';
  const mailId = msg.id || '';
  const epoch = msg.internalDate || Date.now();
  const viajeId = 'VJ-' + String(epoch).substring(0, 13);
  const origenesConocidos = origenesRaw.split(',').map(o => o.trim().toUpperCase()).filter(Boolean);

  // Buscar inicio de "DETALLE DE PEDIDOS INDIVIDUALES:"
  // Puede estar al inicio de línea o pegada a otro texto (ej: "$97.065.106 DETALLE DE PEDIDOS INDIVIDUALES:")
  const detMatch = body.match(/DETALLE DE PEDIDOS INDIVIDUALES:/i);
  if (!detMatch) continue;
  const detStart = detMatch.index + detMatch[0].length;
  const totMatch = body.substring(detStart).match(/\r?\n\s*TOTALES:/i);
  const totStart = totMatch ? detStart + totMatch.index : body.length;
  const detalle = body.substring(detStart, totStart);

  // Split por inicio de pedido: número + (espacios) + RM-/TI-/TIT-/DEVOLUCION
  const pedChunks = detalle.split(/\r?\n(?=\s*\d{1,2}\s+(?:RM-|TI-|TIT-|DEVOLUCI))/i);

  for (const chunk of pedChunks) {
    const clean = chunk.replace(/\s*\r?\n\s*/g, ' ').trim();
    const headMatch = clean.match(/^(\d{1,2})\s+(.+?)\s+(\d{2}\/\d{2}\/\d{4})\s+(.+)/s);
    if (!headMatch) continue;

    const num = parseInt(headMatch[1]);
    const remision = headMatch[2].trim();
    const fechaConsolidacion = headMatch[3];
    const resto = headMatch[4].trim();
    const esDevolucion = /DEVOLUCI[ÓO]N/i.test(remision);

    const tokens = resto.split(/\s+/);
    const empresa = tokens[0] || '';
    const zona = tokens[1] || '';
    const restoUpper = resto.toUpperCase();
    let origen = '', destino = '';

    if (esDevolucion) {
      for (const oc of origenesConocidos) {
        const idx = restoUpper.indexOf(oc);
        if (idx >= 0) { const b = resto.substring(0, idx).trim().split(/\s+/); origen = b.slice(2).join(' ') || ''; destino = oc; break; }
      }
    } else {
      for (const oc of origenesConocidos) {
        const idx = restoUpper.indexOf(oc);
        if (idx >= 0) { origen = oc; const a = resto.substring(idx + oc.length).trim(); const dm = a.match(/^([A-ZÁÉÍÓÚÑÜ\s]+?)\s+\d/); destino = dm ? dm[1].trim() : ''; break; }
      }
    }

    // Normalización de orígenes → Funza
    origen = origen
      .replace(/BOY 3PL SAN DIEGO FUNZA/gi, 'Funza')
      .replace(/CENTRO 3PL FUNZA/gi, 'Funza')
      .replace(/CUN 3PL SAN DIEGO FUNZA/gi, 'Funza')
      .replace(/3PL.*FUNZA/gi, 'Funza')
      .trim();

    const pesoMatch = resto.match(/(\d+\.\d{2})\s+\d+\s+\d+\s+\d+\s+\d+\s+\d+\s+\$/);
    const peso = pesoMatch ? parseFloat(pesoMatch[1]) : 0;
    const valMatch = resto.match(/\$([\d.,]+)/);
    const valorMercancia = valMatch ? valMatch[1] : '';

    const valorIdx = resto.indexOf('$');
    let obsPart = '';
    if (valorIdx > 0) { const am = resto.substring(valorIdx).match(/\$[\d.,]+\s+(.+)/); if (am) obsPart = am[1].trim(); }

    let horarioRaw = '', dias = 'LV', v1Desde = '', v1Hasta = '', v2Desde = '', v2Hasta = '';
    let contacto = '', telefono = '', direccion = '', cliente = '', notas = '', llamarAntes = false, horarioSabado = '';

    if (obsPart) {
      // === HORARIO ===
      // Estrategia: capturar desde primer dígito después de palabra clave
      // hasta encontrar " RM-", " TI-", " TIT-" o fin de string.
      // Usamos lookahead, NO [^:] (porque los horarios tienen ':' como en "12:30")
      const stopBoundary = '(?=\\s+(?:RM|TI|TIT|DEVOLUCION)[-\\s]|$)';
      const hPats = [
        // HORARIO DE RECIBO: L-V: 7 AM A 12 PM ...
        new RegExp('HORARIO[^\\n]*?(?:L[-\\s]*V|M[-\\s]*J|L[-\\s]*S)\\s*:?\\s*(\\d{1,2}.+?)' + stopBoundary, 'i'),
        // HORARIO ... 7:30 AM A ...
        new RegExp('HORARIO[^\\n]*?(\\d{1,2}[\\s:].+?)' + stopBoundary, 'i'),
        // L-V: 8am a 4pm.  (sin palabra HORARIO)
        new RegExp('(?:L[-\\s]V|M[-\\s]J|L[-\\s]S)\\s*:?\\s*(\\d{1,2}.+?)' + stopBoundary, 'i'),
        // Lunes a viernes 7 am a 12:30...
        new RegExp('(?:Lunes a viernes|lunes a viernes|LUNES A VIERNES)[^\\n]*?(?:de\\s+)?(\\d{1,2}.+?)' + stopBoundary, 'i'),
        // horario de recepción: ...
        new RegExp('horario de recepci[oó]n:\\s*(\\d{1,2}.+?)' + stopBoundary, 'i'),
        // recibidos/atención de 7 a 10 am
        new RegExp('(?:recibidos?|atenci[oó]n)[^\\n]*?(?:de\\s+)?(\\d{1,2}.+?)' + stopBoundary, 'i')
      ];
      for (const p of hPats) { 
        const hm = obsPart.match(p); 
        if (hm && hm[1]) { 
          const candidate = hm[1].trim();
          // Descartar si es solo dirección (empieza con número + coma o letra)
          if (/\d/.test(candidate) && !/^\d+\s*,\s*[A-Z]/.test(candidate)) {
            horarioRaw = candidate; 
            break; 
          }
        } 
      }

      // === DÍAS DE ATENCIÓN ===
      const obsUp = obsPart.toUpperCase();

      // NO RECIBEN LOS VIERNES / NO RECIBE JUEVES etc → L-V sin día específico
      let noDay = '';
      const noDayM = obsUp.match(/NO RECIB[EA]N?\s+(?:PEDIDOS\s+)?(?:LOS\s+|EL\s+|DIA\s+)?(LUNES|MARTES|MI[EÉ]RCOLES|JUEVES|VIERNES|S[AÁ]BADO|DOMINGO)/i);
      if (noDayM) {
        const m = { 'LUNES':'L','MARTES':'M','MIERCOLES':'X','MIÉRCOLES':'X','JUEVES':'J','VIERNES':'V','SABADO':'S','SÁBADO':'S','DOMINGO':'D' };
        noDay = m[noDayM[1].toUpperCase()] || '';
      }

      // Detección de patrón de días
      if (/\bMJ\b|\bM[-\s]J\s*:/i.test(obsUp)) {
        // MJ o M-J : lista Martes y Jueves (convención Avgust confirmada)
        dias = 'MJ';
      } else if (/L[-\s]S\b|LUNES A S[AÁ]BADO/i.test(obsUp)) {
        dias = 'LS';
      } else if (/L[-\s]V|LUNES A VIERNES/i.test(obsUp)) {
        dias = 'LV';
        // Si además menciona sábado → LVS
        if (/S[AÁ]BADO|\bS\s*:|Y\s*S\s*:|YS\s*:/i.test(obsUp)) dias = 'LVS';
      } else {
        dias = 'LV';
        if (/S[AÁ]BADO|\bS\s*:|Y\s*S\s*:|YS\s*:/i.test(obsUp)) dias = 'LVS';
      }

      // Si hay exclusión explícita (ej: "NO RECIBEN LOS VIERNES"), marcar
      if (noDay) {
        // Mapear a código personalizado: LV-V = L,M,X,J (excluye V)
        dias = dias + '-' + noDay;
      }

      // === VENTANAS ===
      // Solo extraer ventanas SI hay horarioRaw válido. Evita capturar números de tel/dir
      const pairRx = /(\d{1,2}(?::\d{2})?\s*(?:AM|PM|M|am|pm|a\.?m\.?|p\.?m\.?)?)\s*(?:a|-|A|–|al?)\s*(\d{1,2}(?::\d{2})?\s*(?:AM|PM|M|am|pm|a\.?m\.?|p\.?m\.?)?)/gi;
      const ventanas = []; let tm;
      if (horarioRaw) {
        while ((tm = pairRx.exec(horarioRaw)) !== null) ventanas.push({ desde: normTime(tm[1]), hasta: normTime(tm[2]) });
      }
      if (ventanas.length >= 1) { v1Desde = ventanas[0].desde; v1Hasta = ventanas[0].hasta; }
      if (ventanas.length >= 2) { v2Desde = ventanas[1].desde; v2Hasta = ventanas[1].hasta; }

      // === SÁBADO ===
      const sabM = obsPart.match(/[Ss][AÁaá]bado[s]?[:\s]+(?:de\s+)?(\d{1,2}(?::\d{2})?\s*(?:AM|am|a\.?m)?)\s*(?:a|-|A|–)\s*(\d{1,2}(?::\d{2})?\s*(?:AM|PM|am|pm|M)?)/i);
      if (sabM) horarioSabado = normTime(sabM[1]) + '-' + normTime(sabM[2]);
      else { const s2 = obsPart.match(/\bS\s*:\s*(\d{1,2}(?::\d{2})?)\s*(?:a|-|–)\s*(\d{1,2}(?::\d{2})?\s*(?:AM|PM|am|pm|aM)?)/i); if (s2) horarioSabado = normTime(s2[1]) + '-' + normTime(s2[2]); }

      // === CONTACTO ===
      const cM = obsPart.match(/CONTACTO:\s*([^,/]+)/i); if (cM) contacto = cM[1].trim();
      const tM = obsPart.match(/CEL:\s*([\d\s\-]+)/i); if (tM) telefono = tM[1].trim().split(/\s*-\s*/)[0];
      if (!telefono) { const t2 = obsPart.match(/(3\d{9})/); if (t2) telefono = t2[1]; }
      const clM = obsPart.match(/DESTINO:\s*([^,]+)/i); if (clM) cliente = clM[1].trim();

      // === DIRECCIÓN ===
      const remKey = esDevolucion ? 'DEVOLUCION' : remision.split('/')[0].split(' ')[0];
      const dirP = obsPart.split(new RegExp(remKey.replace(/[\-\/]/g, '[\\-\\/]?') + '[^:]*:', 'i')).filter(Boolean);
      if (dirP.length >= 2) direccion = dirP[dirP.length - 1].trim();

      // === NOTAS ===
      if (/LLAMAR.*(?:DI|DÍ)A.*ANTERIOR/i.test(obsPart)) { llamarAntes = true; notas += 'LLAMAR DÍA ANTERIOR. '; }
      if (/avisar.*(?:día|dia).*anticipaci[oó]n/i.test(obsPart)) { llamarAntes = true; notas += 'AVISAR DÍA ANTERIOR. '; }
      if (/NO CONFUNDIR/i.test(obsPart)) { const nc = obsPart.match(/NO CONFUNDIR[^/]*/i); if (nc) notas += nc[0].trim() + '. '; }
      if (/RECOGER/i.test(obsPart)) notas += 'RECOGER (devolución). ';
      if (/LLAMAR.*(?:CONTACTO|ANTES)/i.test(obsPart) && !llamarAntes) notas += 'LLAMAR ANTES DE ENTREGA. ';
      if (noDayM) notas += 'NO RECIBE ' + noDayM[1].toUpperCase() + '. ';
    }

    results.push({ json: {
      VIAJE_ID: viajeId, NUMERO: num, REMISION: remision, FECHA_CONSOLIDACION: fechaConsolidacion,
      EMPRESA: empresa, ZONA: zona, ORIGEN: origen || 'Funza', DESTINO: destino,
      PESO_KG: peso, VALOR_MERCANCIA: valorMercancia, ES_DEVOLUCION: esDevolucion ? 'SI' : 'NO',
      DIAS_ATENCION: dias, HORARIO_RAW: horarioRaw, V1_DESDE: v1Desde, V1_HASTA: v1Hasta,
      V2_DESDE: v2Desde, V2_HASTA: v2Hasta, HORARIO_SABADO: horarioSabado,
      CLIENTE: cliente, CONTACTO: contacto, TELEFONO: telefono, DIRECCION: direccion,
      NOTAS: notas.trim(), LLAMAR_ANTES: llamarAntes ? 'SI' : 'NO',
      VIAJE_EMPRESAS: empresas, VIAJE_ZONAS: zonas, VIAJE_FECHA_CARGUE: fechaCargue,
      VIAJE_PESO_TOTAL: pesoTotal, VIAJE_VALOR_TOTAL: valorTotal, VIAJE_CANT_PEDIDOS: cantPedidos,
      MAIL_SUBJECT: subject, MAIL_ID: mailId,
    }});
  }
}

function normTime(t) {
  if (!t) return '';
  t = t.trim().toUpperCase().replace(/\./g, '');
  const m = t.match(/(\d{1,2})(?::(\d{2}))?\s*(AM|PM|M|A|P)?/);
  if (!m) return '';
  let h = parseInt(m[1]); const min = m[2] ? parseInt(m[2]) : 0; const ap = m[3] || '';
  if (ap === 'M' && h === 12) {}
  else if (ap === 'PM' || ap === 'P') { if (h < 12) h += 12; }
  else if (ap === 'AM' || ap === 'A') { if (h === 12) h = 0; }
  else { if (h >= 1 && h <= 6) h += 12; }
  return String(h).padStart(2, '0') + ':' + String(min).padStart(2, '0');
}

console.log('[Parser v2] TOTAL pedidos:', results.length);
return results;
